verbs.source:
verb :apply(perms, mods) rxd {
  // LambdaCore $perm_utils:apply (#42), faithfully ported. Apply a
  // perm-modification string on top of an existing perm string.
  // `mods` is one of:
  //   - absolute perms (no leading +/-/!): returned verbatim, replacing
  //     `perms` entirely. e.g. apply("rxd", "rw") -> "rw".
  //   - a sequence of `+letters`, `-letters`, `!letters` segments:
  //     `+` adds the listed flag letters, `-`/`!` (equivalent) removes
  //     them. Letters already present aren't doubled; letters not
  //     present aren't an error. apply("rxd", "+w-x") -> "rdw".
  // Used by @chmod for the `+r-w` form.
  if (typeof(perms) != "string") { perms = ""; }
  if (typeof(mods) != "string" || mods == "") { return mods; }
  let first = str_slice(mods, 1, 1);
  let is_mod = false;
  if (first == "+") { is_mod = true; }
  if (first == "-") { is_mod = true; }
  if (first == "!") { is_mod = true; }
  if (!is_mod) {
    return mods;
  }
  let i = 1;
  let n = length(mods);
  while (i <= n) {
    let op = str_slice(mods, i, i);
    let add_mode = false;
    if (op == "+") { add_mode = true; }
    i = i + 1;
    while (i <= n) {
      let ch = str_slice(mods, i, i);
      if (ch == "+") { break; }
      if (ch == "-") { break; }
      if (ch == "!") { break; }
      if (add_mode) {
        if (str_index(perms, ch) == 0) { perms = perms + ch; }
      } else {
        // Remove every occurrence of `ch` from perms. str_index returns
        // 1-based positions; loop until none remain.
        let pos = str_index(perms, ch);
        while (pos > 0) {
          let head = "";
          if (pos > 1) { head = str_slice(perms, 1, pos - 1); }
          let tail = "";
          if (pos < length(perms)) { tail = str_slice(perms, pos + 1); }
          perms = head + tail;
          pos = str_index(perms, ch);
        }
      }
      i = i + 1;
    }
  }
  return perms;
}
